#include<bits/stdc++.h>
using namespace std;

int main()
{
    long double ans=0,len=0;
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        char ch;
        cin>>ch;
        if(ch=='o')
        {
            ans=ans+len*2+1;
            len+=1;
        }
        else if(ch=='x')
        {
            len=0;
        }
        else
        {
            ans=ans+len+0.5;
            len=(len+1)/2.0;
        }
    }
    printf("%.4llf",ans);
    return 0;
}
